//+------------------------------------------------------------------+
#property copyright "Jose's Trading Suite"
#property link      ""
#property version   "1.00"
#property description "Opening Range Breakout - EURUSD London Open"

#include <Trade\Trade.mqh>

//+------------------------------------------------------------------+
//| Enumeracion de direccion de trading                              |
//+------------------------------------------------------------------+
enum ENUM_ORB_DIRECTION
{
   DIR_BOTH      = 0,  // Ambos: BUY STOP + SELL STOP
   DIR_BUY_ONLY  = 1,  // Solo compras: BUY STOP en el High
   DIR_SELL_ONLY = 2   // Solo ventas: SELL STOP en el Low
};

//+------------------------------------------------------------------+
//| Maquina de estados                                               |
//+------------------------------------------------------------------+
enum EA_STATE
{
   STATE_IDLE,              // En espera del inicio de sesion
   STATE_BUILDING_RANGE,    // Acumulando velas del rango ORB
   STATE_WAITING_BREAKOUT,  // Ordenes pendientes activas
   STATE_MANAGING_TRADE     // Gestionando trade abierto
};

//+------------------------------------------------------------------+
//| Inputs                                                           |
//+------------------------------------------------------------------+
input group "=== CONFIGURACION DE SESION ==="
input int    InpSessionHour    = 8;        // Hora inicio GMT (London=8, NY=13)
input int    InpSessionMinute  = 0;        // Minuto inicio

input group "=== RANGO ORB ==="
input int    InpRangeCandles   = 3;        // Velas M5 del rango (3=15min, 6=30min)

input group "=== PARAMETROS DE TRADE ==="
input int    InpTP_Pips        = 20;       // Take Profit en pips (1 pip = 0.0001)
input int    InpSL_Pips        = 15;       // Stop Loss en pips
input int    InpBE_Pips        = 10;       // Breakeven trigger pips (0=desactivado)
input ENUM_ORB_DIRECTION InpTradeDirection = DIR_BOTH; // Direccion de trading

input group "=== GESTION DE RIESGO ==="
input double InpRiskUSD        = 5.0;      // Riesgo fijo USD por trade
input bool   InpUsePercentRisk = false;    // Usar % de balance (true) o USD fijo (false)
input double InpRiskPercent    = 1.0;      // % de riesgo si UsePercentRisk=true
input bool   InpOnlyOnePerDay  = true;     // Solo un trade por sesion diaria

input group "=== COMPLIANCE FUNDEDNEXT ==="
input bool   InpUseDDLimit     = true;     // Activar control de drawdown
input double InpDailyDDLimit   = 4.5;      // Limite DD diario % (FundedNext limite: 5%)
input double InpTotalDDLimit   = 9.5;      // Limite DD total % (FundedNext limite: 10%)
input int    InpOrderTimeout   = 20;       // Hora GMT para cancelar ordenes sin activar

input group "=== FILTRO DE DIAS ==="
input bool   InpAllowMonday    = true;
input bool   InpAllowTuesday   = true;
input bool   InpAllowWednesday = true;
input bool   InpAllowThursday  = true;
input bool   InpAllowFriday    = true;
input bool   InpAllowSaturday  = false;
input bool   InpAllowSunday    = false;

input group "=== IDENTIFICACION ==="
input ulong  InpMagicNumber    = 20250404;
input string InpComment        = "ORB_EUR";

//+------------------------------------------------------------------+
//| Variables globales                                               |
//+------------------------------------------------------------------+
CTrade    g_trade;
EA_STATE  g_state            = STATE_IDLE;

// Rango ORB
double    g_rangeHigh        = 0.0;
double    g_rangeLow         = DBL_MAX;
datetime  g_sessionStart     = 0;
datetime  g_rangeEndTime     = 0;

// Control de trades
datetime  g_lastTradeDate    = 0;
int       g_totalTrades      = 0;
ulong     g_activeTicket     = 0;

// Control de drawdown
double    g_initialBalance   = 0.0;
double    g_dailyStartEquity = 0.0;
datetime  g_dailyDate        = 0;

// CSV Logger
int       g_csvHandle        = INVALID_HANDLE;

// Para CSV: guardar datos de entrada del trade activo
double    g_tradeEntryPrice  = 0.0;
double    g_tradeSLPrice     = 0.0;
double    g_tradeTPPrice     = 0.0;
string    g_tradeDirection   = "";
datetime  g_tradeOpenTime    = 0;

//+------------------------------------------------------------------+
//| OnInit                                                           |
//+------------------------------------------------------------------+
int OnInit()
{
   //--- Validaciones criticas
   if(_Period != PERIOD_M5)
   {
      Alert("ERROR: Este EA requiere timeframe M5. Actual: ", EnumToString(_Period));
      return INIT_FAILED;
   }

   if(InpTP_Pips <= 0 || InpSL_Pips <= 0)
   {
      Alert("ERROR: InpTP_Pips y InpSL_Pips deben ser > 0");
      return INIT_FAILED;
   }

   if(InpRangeCandles < 1 || InpRangeCandles > 24)
   {
      Alert("ERROR: InpRangeCandles debe estar entre 1 y 24");
      return INIT_FAILED;
   }

   //--- Advertencia de simbolo
   if(StringFind(_Symbol, "EURUSD") < 0)
      Print("ADVERTENCIA: EA optimizado para EURUSD. Simbolo actual: ", _Symbol);

   //--- Configurar CTrade
   g_trade.SetExpertMagicNumber(InpMagicNumber);
   g_trade.SetDeviationInPoints(20);    // 2 pips de slippage maximo
   g_trade.SetTypeFilling(ORDER_FILLING_IOC);
   g_trade.LogLevel(LOG_LEVEL_ERRORS);

   //--- Balances iniciales
   g_initialBalance    = AccountInfoDouble(ACCOUNT_BALANCE);
   g_dailyStartEquity  = AccountInfoDouble(ACCOUNT_EQUITY);
   g_dailyDate         = TimeCurrent();

   //--- Inicializar CSV
   InitCSVLogger();

   //--- Log de inicio
   Print("========================================");
   Print("ORB_Breakout_EURUSD_v1.0 INICIADO");
   Print("Simbolo: ", _Symbol, " | Timeframe: M5");
   Print("Sesion: ", PadInt(InpSessionHour), ":", PadInt(InpSessionMinute), " GMT");
   Print("Rango: ", InpRangeCandles, " velas M5 (", InpRangeCandles * 5, " min)");
   Print("TP: ", InpTP_Pips, " pips | SL: ", InpSL_Pips, " pips | BE: ", InpBE_Pips, " pips");
   Print("RR: 1:", DoubleToString((double)InpTP_Pips / InpSL_Pips, 2));
   Print("Riesgo: ", InpUsePercentRisk ? (DoubleToString(InpRiskPercent,1)+"%") : ("$"+DoubleToString(InpRiskUSD,2)));
   Print("Balance inicial: $", DoubleToString(g_initialBalance, 2));
   Print("FundedNext DD limites: Diario ", InpDailyDDLimit, "% | Total ", InpTotalDDLimit, "%");
   Print("========================================");

   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| OnDeinit                                                         |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   CancelAllPending();
   if(g_csvHandle != INVALID_HANDLE)
      FileClose(g_csvHandle);
   Print("EA detenido. Razon: ", reason, " | Total trades: ", g_totalTrades);
}

//+------------------------------------------------------------------+
//| OnTick - Logica principal                                        |
//+------------------------------------------------------------------+
void OnTick()
{
   //--- 1. Actualizar referencia de balance diario
   RefreshDailyBalance();

   //--- 2. Control de drawdown FundedNext
   if(InpUseDDLimit && IsDrawdownExceeded())
      return;

   //--- 3. Filtro de dia de la semana
   if(!IsDayAllowed())
   {
      if(g_state != STATE_IDLE) ResetToIdle();
      return;
   }

   //--- 4. Maquina de estados
   switch(g_state)
   {
      case STATE_IDLE:            HandleIdle();          break;
      case STATE_BUILDING_RANGE:  HandleBuildingRange(); break;
      case STATE_WAITING_BREAKOUT: HandleWaiting();      break;
      case STATE_MANAGING_TRADE:  HandleManaging();      break;
   }
}

//+------------------------------------------------------------------+
//| ESTADO: IDLE                                                     |
//| Detecta el inicio de la sesion y transiciona a BUILDING_RANGE    |
//+------------------------------------------------------------------+
void HandleIdle()
{
   datetime now = TimeCurrent();

   //--- Construir datetime de inicio de sesion para hoy
   MqlDateTime dt;
   TimeToStruct(now, dt);
   dt.hour = InpSessionHour;
   dt.min  = InpSessionMinute;
   dt.sec  = 0;
   datetime sessionToday = StructToTime(dt);

   //--- Detectar apertura de sesion: ventana de 60 segundos
   if(now >= sessionToday && now < sessionToday + 60)
   {
      //--- Verificar que no hayamos ya operado hoy (si OnlyOnePerDay)
      if(InpOnlyOnePerDay && g_lastTradeDate == GetTodayDate())
         return;

      g_sessionStart = sessionToday;
      g_rangeEndTime = sessionToday + (long)InpRangeCandles * 5 * 60;
      g_rangeHigh    = 0.0;
      g_rangeLow     = DBL_MAX;
      g_state        = STATE_BUILDING_RANGE;

      Print("[SESION] Iniciada: ", TimeToString(g_sessionStart),
            " | Rango cierra: ", TimeToString(g_rangeEndTime));
   }
}

//+------------------------------------------------------------------+
//| ESTADO: BUILDING_RANGE                                           |
//| Acumula High/Low de velas cerradas desde el inicio de sesion     |
//+------------------------------------------------------------------+
void HandleBuildingRange()
{
   datetime now = TimeCurrent();

   //--- Acumular high/low de velas dentro de la ventana del rango
   //--- Iteramos sobre velas cerradas (index > 0)
   for(int i = 1; i <= InpRangeCandles + 5; i++)
   {
      datetime candleOpen  = iTime(_Symbol, PERIOD_M5, i);
      datetime candleClose = candleOpen + 5 * 60 - 1;

      //--- Solo velas que empezaron dentro de la ventana de sesion
      if(candleOpen < g_sessionStart) break;
      if(candleOpen >= g_rangeEndTime) continue;

      double hi = iHigh(_Symbol, PERIOD_M5, i);
      double lo = iLow(_Symbol, PERIOD_M5, i);

      if(hi > g_rangeHigh) g_rangeHigh = hi;
      if(lo < g_rangeLow)  g_rangeLow  = lo;
   }

   //--- Rango completo cuando ha pasado el tiempo de InpRangeCandles velas
   if(now >= g_rangeEndTime)
   {
      bool rangeValid = (g_rangeHigh > 0.0 && g_rangeLow < DBL_MAX && g_rangeHigh > g_rangeLow);

      if(rangeValid)
      {
         double rangePips = (g_rangeHigh - g_rangeLow) / (10.0 * _Point);
         Print("[RANGO] High=", g_rangeHigh, " Low=", g_rangeLow,
               " | Amplitud: ", DoubleToString(rangePips, 1), " pips");

         //--- Colocar ordenes pendientes
         PlacePendingOrders();
         g_state = STATE_WAITING_BREAKOUT;
      }
      else
      {
         Print("[RANGO] ERROR: Rango invalido. High=", g_rangeHigh, " Low=", g_rangeLow, ". Reset.");
         ResetToIdle();
      }
   }
}

//+------------------------------------------------------------------+
//| ESTADO: WAITING_BREAKOUT                                         |
//| Espera que una orden pendiente se active                         |
//+------------------------------------------------------------------+
void HandleWaiting()
{
   //--- Verificar si hay posicion activa del EA
   ulong ticket = GetActivePositionTicket();

   if(ticket > 0)
   {
      //--- Breakout activado: cancelar la otra orden pendiente
      CancelAllPending();

      g_activeTicket  = ticket;
      g_lastTradeDate = GetTodayDate();
      g_totalTrades++;

      //--- Guardar datos del trade para el CSV
      if(PositionSelectByTicket(ticket))
      {
         g_tradeEntryPrice = PositionGetDouble(POSITION_PRICE_OPEN);
         g_tradeSLPrice    = PositionGetDouble(POSITION_SL);
         g_tradeTPPrice    = PositionGetDouble(POSITION_TP);
         g_tradeOpenTime   = (datetime)PositionGetInteger(POSITION_TIME);
         g_tradeDirection  = (PositionGetInteger(POSITION_TYPE) == POSITION_TYPE_BUY) ? "BUY" : "SELL";
      }

      g_state = STATE_MANAGING_TRADE;
      Print("[BREAKOUT] Trade #", g_totalTrades, " activado | Dir: ", g_tradeDirection,
            " | Entry: ", g_tradeEntryPrice, " | SL: ", g_tradeSLPrice, " | TP: ", g_tradeTPPrice);
      return;
   }

   //--- Timeout: cancelar ordenes si pasan las InpOrderTimeout:00 GMT sin activacion
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   if(dt.hour >= InpOrderTimeout)
   {
      Print("[TIMEOUT] Ordenes canceladas a las ", InpOrderTimeout, ":00 GMT sin activacion.");
      CancelAllPending();
      g_state = STATE_IDLE;
   }
}

//+------------------------------------------------------------------+
//| ESTADO: MANAGING_TRADE                                           |
//| Gestiona el trade activo: breakeven, cierre                      |
//+------------------------------------------------------------------+
void HandleManaging()
{
   ulong ticket = GetActivePositionTicket();

   if(ticket > 0)
   {
      //--- Trade activo: aplicar breakeven si corresponde
      ApplyBreakeven(ticket);
   }
   else
   {
      //--- Trade cerrado (TP, SL o manual)
      LogClosedTrade();
      g_state = STATE_IDLE;
      Print("[TRADE CERRADO] Trade #", g_totalTrades, " finalizado. Estado: IDLE.");
   }
}

//+------------------------------------------------------------------+
//| Colocar ordenes pendientes en los extremos del rango             |
//+------------------------------------------------------------------+
void PlacePendingOrders()
{
   double lots = CalculateLotSize(InpSL_Pips);
   if(lots <= 0)
   {
      Print("[ERROR] Lotes calculados = 0. Verificar configuracion de riesgo.");
      ResetToIdle();
      return;
   }

   int    digits = (int)SymbolInfoInteger(_Symbol, SYMBOL_DIGITS);
   double spread = (double)SymbolInfoInteger(_Symbol, SYMBOL_SPREAD) * _Point;
   double pip    = 10.0 * _Point;  // 1 pip = 0.0001 = 10 points en broker 5 digitos

   bool orderPlaced = false;

   //--- BUY STOP: encima del High del rango
   if(InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_BUY_ONLY)
   {
      double buyEntry = NormalizeDouble(g_rangeHigh + spread, digits);
      double buyTP    = NormalizeDouble(buyEntry + InpTP_Pips * pip, digits);
      double buySL    = NormalizeDouble(buyEntry - InpSL_Pips * pip, digits);

      bool ok = g_trade.BuyStop(lots, buyEntry, _Symbol, buySL, buyTP,
                                ORDER_TIME_DAY, 0, InpComment);
      if(ok)
      {
         Print("[ORD] BUY STOP: entry=", buyEntry, " SL=", buySL, " TP=", buyTP,
               " lots=", DoubleToString(lots, 2));
         orderPlaced = true;
      }
      else
         Print("[ERROR] BUY STOP: ", g_trade.ResultRetcode(), " - ", g_trade.ResultRetcodeDescription());
   }

   //--- SELL STOP: debajo del Low del rango
   if(InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_SELL_ONLY)
   {
      double sellEntry = NormalizeDouble(g_rangeLow - spread, digits);
      double sellTP    = NormalizeDouble(sellEntry - InpTP_Pips * pip, digits);
      double sellSL    = NormalizeDouble(sellEntry + InpSL_Pips * pip, digits);

      bool ok = g_trade.SellStop(lots, sellEntry, _Symbol, sellSL, sellTP,
                                 ORDER_TIME_DAY, 0, InpComment);
      if(ok)
      {
         Print("[ORD] SELL STOP: entry=", sellEntry, " SL=", sellSL, " TP=", sellTP,
               " lots=", DoubleToString(lots, 2));
         orderPlaced = true;
      }
      else
         Print("[ERROR] SELL STOP: ", g_trade.ResultRetcode(), " - ", g_trade.ResultRetcodeDescription());
   }

   if(!orderPlaced)
   {
      Print("[ERROR] Ninguna orden colocada exitosamente. Reset.");
      ResetToIdle();
   }
}

//+------------------------------------------------------------------+
//| Aplicar Breakeven al trade activo                                |
//+------------------------------------------------------------------+
void ApplyBreakeven(ulong ticket)
{
   if(InpBE_Pips <= 0) return;
   if(!PositionSelectByTicket(ticket)) return;

   double openPrice  = PositionGetDouble(POSITION_PRICE_OPEN);
   double currentSL  = PositionGetDouble(POSITION_SL);
   double currentTP  = PositionGetDouble(POSITION_TP);
   double bidAsk     = PositionGetDouble(POSITION_PRICE_CURRENT);
   int    digits     = (int)SymbolInfoInteger(_Symbol, SYMBOL_DIGITS);
   double pip        = 10.0 * _Point;
   ENUM_POSITION_TYPE posType = (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);

   double beDist = InpBE_Pips * pip;

   if(posType == POSITION_TYPE_BUY)
   {
      //--- Mover SL a breakeven cuando el precio sube InpBE_Pips
      if(bidAsk >= openPrice + beDist && currentSL < openPrice - _Point)
      {
         double newSL = NormalizeDouble(openPrice + 1 * _Point, digits); // 0.1 pip sobre entrada
         if(g_trade.PositionModify(ticket, newSL, currentTP))
            Print("[BE] BUY breakeven aplicado: nuevo SL=", newSL);
      }
   }
   else if(posType == POSITION_TYPE_SELL)
   {
      //--- Mover SL a breakeven cuando el precio baja InpBE_Pips
      if(bidAsk <= openPrice - beDist && currentSL > openPrice + _Point)
      {
         double newSL = NormalizeDouble(openPrice - 1 * _Point, digits);
         if(g_trade.PositionModify(ticket, newSL, currentTP))
            Print("[BE] SELL breakeven aplicado: nuevo SL=", newSL);
      }
   }
}

//+------------------------------------------------------------------+
//| Calcular tamano de lote para EURUSD                              |
//|                                                                  |
//| EURUSD en cuenta USD: 1 pip (0.0001) = $10 exactos por lote     |
//| Formula: Lotes = RiesgoUSD / (SL_pips x $10/pip)                |
//| Ejemplo: $5 riesgo / (15 pips x $10) = 0.033 -> 0.03 lotes      |
//+------------------------------------------------------------------+
double CalculateLotSize(int slPips)
{
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = InpUsePercentRisk ? (balance * InpRiskPercent / 100.0) : InpRiskUSD;

   if(riskAmount <= 0)
   {
      Print("[ERROR] riskAmount <= 0: ", riskAmount);
      return 0;
   }

   //--- Valor por pip por lote usando SymbolInfo (preciso y compatible con brokers)
   double tickVal  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSz   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickSz == 0 || tickVal == 0)
   {
      Print("[ERROR] tickVal=", tickVal, " tickSz=", tickSz, " - SymbolInfo no disponible");
      return 0;
   }

   //--- Valor monetario de 1 pip (0.0001) por lote estandar
   double pipValue = tickVal * (0.0001 / tickSz);
   //--- Para EURUSD en USD: pipValue = $10.00 por lote (constante)

   double lots = riskAmount / ((double)slPips * pipValue);

   //--- Normalizar segun especificaciones del simbolo
   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

   Print("[SIZING] Riesgo=$", DoubleToString(riskAmount, 2),
         " | SL=", slPips, "pips | PipValue=$", DoubleToString(pipValue, 2),
         " | Lotes=", DoubleToString(lots, 2));

   return lots;
}

//+------------------------------------------------------------------+
//| Obtener ticket de posicion activa del EA                        |
//+------------------------------------------------------------------+
ulong GetActivePositionTicket()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      ulong ticket = PositionGetTicket(i);
      if(PositionSelectByTicket(ticket))
      {
         if(PositionGetInteger(POSITION_MAGIC) == (long)InpMagicNumber &&
            PositionGetString(POSITION_SYMBOL) == _Symbol)
            return ticket;
      }
   }
   return 0;
}

//+------------------------------------------------------------------+
//| Cancelar todas las ordenes pendientes del EA                    |
//+------------------------------------------------------------------+
void CancelAllPending()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      ulong ticket = OrderGetTicket(i);
      if(!OrderSelect(ticket)) continue;
      if(OrderGetInteger(ORDER_MAGIC) != (long)InpMagicNumber) continue;
      if(OrderGetString(ORDER_SYMBOL) != _Symbol) continue;

      if(g_trade.OrderDelete(ticket))
         Print("[CANCEL] Orden pendiente eliminada: #", ticket);
      else
         Print("[ERROR] No se pudo eliminar orden #", ticket, ": ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//| Verificar si el dia actual esta permitido                       |
//+------------------------------------------------------------------+
bool IsDayAllowed()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);

   switch(dt.day_of_week)
   {
      case 0: return InpAllowSunday;
      case 1: return InpAllowMonday;
      case 2: return InpAllowTuesday;
      case 3: return InpAllowWednesday;
      case 4: return InpAllowThursday;
      case 5: return InpAllowFriday;
      case 6: return InpAllowSaturday;
   }
   return false;
}

//+------------------------------------------------------------------+
//| Actualizar balance diario de referencia                         |
//+------------------------------------------------------------------+
void RefreshDailyBalance()
{
   datetime today = GetTodayDate();
   if(today > StringToTime(TimeToString(g_dailyDate, TIME_DATE)))
   {
      g_dailyStartEquity = AccountInfoDouble(ACCOUNT_EQUITY);
      g_dailyDate        = TimeCurrent();
   }
}

//+------------------------------------------------------------------+
//| Verificar si se superaron los limites de DD (FundedNext)        |
//+------------------------------------------------------------------+
bool IsDrawdownExceeded()
{
   double equity = AccountInfoDouble(ACCOUNT_EQUITY);

   //--- DD Diario: desde equity al inicio del dia
   if(g_dailyStartEquity > 0)
   {
      double dailyDD = (g_dailyStartEquity - equity) / g_dailyStartEquity * 100.0;
      if(dailyDD >= InpDailyDDLimit)
      {
         static datetime lastWarn = 0;
         if(TimeCurrent() - lastWarn > 300)
         {
            Print("[LIMITE DD DIARIO] ", DoubleToString(dailyDD, 2), "% >= ", InpDailyDDLimit, "% | Trading detenido.");
            lastWarn = TimeCurrent();
         }
         CancelAllPending();
         return true;
      }
   }

   //--- DD Total: desde balance inicial del EA
   if(g_initialBalance > 0)
   {
      double totalDD = (g_initialBalance - equity) / g_initialBalance * 100.0;
      if(totalDD >= InpTotalDDLimit)
      {
         Print("[LIMITE DD TOTAL] ", DoubleToString(totalDD, 2), "% >= ", InpTotalDDLimit, "% | Trading detenido.");
         CancelAllPending();
         return true;
      }
   }

   return false;
}

//+------------------------------------------------------------------+
