//+------------------------------------------------------------------+
//| Registrar trade cerrado en CSV                                  |
//+------------------------------------------------------------------+
void LogClosedTrade()
{
   if(g_csvHandle == INVALID_HANDLE) return;

   //--- Buscar en historial reciente (48h)
   datetime searchFrom = TimeCurrent() - 86400 * 2;
   if(!HistorySelect(searchFrom, TimeCurrent())) return;

   //--- Encontrar el ultimo deal OUT del EA
   for(int i = HistoryDealsTotal() - 1; i >= 0; i--)
   {
      ulong dTicket = HistoryDealGetTicket(i);
      if(!HistoryDealSelect(dTicket)) continue;
      if(HistoryDealGetInteger(dTicket, DEAL_MAGIC)  != (long)InpMagicNumber) continue;
      if(HistoryDealGetString(dTicket,  DEAL_SYMBOL) != _Symbol) continue;
      if(HistoryDealGetInteger(dTicket, DEAL_ENTRY)  != DEAL_ENTRY_OUT) continue;

      //--- Datos del deal de cierre
      double grossProfit = HistoryDealGetDouble(dTicket, DEAL_PROFIT);
      double commission  = HistoryDealGetDouble(dTicket, DEAL_COMMISSION);
      double swap        = HistoryDealGetDouble(dTicket, DEAL_SWAP);
      double netProfit   = grossProfit + commission + swap;
      double exitPrice   = HistoryDealGetDouble(dTicket, DEAL_PRICE);
      double lots        = HistoryDealGetDouble(dTicket, DEAL_VOLUME);
      datetime closeTime = (datetime)HistoryDealGetInteger(dTicket, DEAL_TIME);

      //--- Calcular amplitud del rango
      double rangePips = (g_rangeHigh > 0.0 && g_rangeLow < DBL_MAX) ?
                         (g_rangeHigh - g_rangeLow) / (10.0 * _Point) : 0.0;

      //--- Dia de la semana del cierre
      MqlDateTime dt;
      TimeToStruct(closeTime, dt);

      //--- Resultado
      string result = (netProfit > 0.01) ? "WIN" : (netProfit < -0.01) ? "LOSS" : "BE";

      //--- Filtro de direccion como string
      string dirFilter = (InpTradeDirection == DIR_BOTH) ? "BOTH" :
                         (InpTradeDirection == DIR_BUY_ONLY) ? "BUY_ONLY" : "SELL_ONLY";

      FileWrite(g_csvHandle,
                g_totalTrades,
                GetDayName(dt.day_of_week),
                dt.day_of_week,
                TimeToString(g_tradeOpenTime, TIME_DATE | TIME_MINUTES),
                TimeToString(closeTime, TIME_DATE | TIME_MINUTES),
                g_tradeDirection,
                DoubleToString(g_tradeEntryPrice, _Digits),
                DoubleToString(g_tradeSLPrice, _Digits),
                DoubleToString(g_tradeTPPrice, _Digits),
                DoubleToString(exitPrice, _Digits),
                DoubleToString(lots, 2),
                DoubleToString(grossProfit, 2),
                DoubleToString(commission, 2),
                DoubleToString(swap, 4),
                DoubleToString(netProfit, 2),
                result,
                DoubleToString(g_rangeHigh, _Digits),
                DoubleToString(g_rangeLow < DBL_MAX ? g_rangeLow : 0.0, _Digits),
                DoubleToString(rangePips, 1),
                DoubleToString(AccountInfoDouble(ACCOUNT_BALANCE), 2),
                DoubleToString(AccountInfoDouble(ACCOUNT_EQUITY), 2),
                InpTP_Pips,
                InpSL_Pips,
                InpBE_Pips,
                InpRangeCandles,
                InpSessionHour,
                dirFilter,
                DoubleToString(InpRiskUSD, 2),
                InpUsePercentRisk ? "true" : "false",
                DoubleToString(InpRiskPercent, 1));

      Print("[LOG CSV] Trade #", g_totalTrades, " | ", result,
            " | Net: $", DoubleToString(netProfit, 2),
            " | Dir: ", g_tradeDirection,
            " | Comision: $", DoubleToString(commission, 2));
      break;
   }
}
