{"language": "plaintext", "code": "//+------------------------------------------------------------------+
//|                                   ORB_Breakout_EURUSD_v1.0.mq5  |
//|                    Opening Range Breakout Expert Advisor v1.00   |
//|                              Jose's Trading Suite - Abril 2026   |
//+------------------------------------------------------------------+
//|  DESCRIPCION:                                                    |
//|  EA basado en el concepto Opening Range Breakout (ORB).          |
//|  Define el rango de las primeras N velas de sesion y coloca      |
//|  ordenes pendientes en sus extremos. Al activarse una direccion, |
//|  la opuesta se cancela automaticamente. Gestion de riesgo        |
//|  integrada por USD o % del balance.                              |
//|                                                                  |
//|  ADAPTACION PARA EURUSD (base: ORB_BreakoutEA_v1.1 - XAUUSD):  |
//|  Cambios respecto al original v1.1:                              |
//|    1. InpSessionHour   = 8   → London Open (era 9)              |
//|    2. InpTP_Pips       = 20  → rango tipico EURUSD (era 100)    |
//|    3. InpSL_Pips       = 15  → RR 1.33:1 positivo   (era 50)    |
//|    4. InpBE_Pips       = 10  → BE activo por defecto (era 50)   |
//|    5. InpRiskUSD       = 5   → ajustado a cuenta    (era 50)    |
//|    6. InpComment       = "ORB_EUR"                  (era ORB_EA)|
//|    7. InpMagicNumber   = 20250404                               |
//|  TODA la logica interna es identica al v1.1.                    |
//|                                                                  |
//|  NOTA PIP: 1 pip = 10 puntos (brokers modernos 5 decimales)     |
//|  Para EURUSD 5 decimales: 1 pip = 0.0001.                       |
//|  SL=15 pips en EURUSD = 0.0015 de movimiento de precio.         |
//+------------------------------------------------------------------+
#property copyright   "Jose's Trading Suite"
#property link        ""
#property version     "1.00"
#property description "Opening Range Breakout EA v1.0 - EURUSD London Open"

#include <Trade\Trade.mqh>

//+------------------------------------------------------------------+
//|  ENUM: Direccion de las ordenes ORB                              |
//+------------------------------------------------------------------+
enum ENUM_ORB_DIRECTION
{
   DIR_BOTH      = 0,  // Ambos — BUY STOP + SELL STOP
   DIR_BUY_ONLY  = 1,  // Solo compras — BUY STOP en el High
   DIR_SELL_ONLY = 2   // Solo ventas  — SELL STOP en el Low
};

//+------------------------------------------------------------------+
//|  PARAMETROS DE ENTRADA                                           |
//+------------------------------------------------------------------+

input group "=== CONFIGURACION DEL RANGO ORB ==="
input int     InpRangeCandles    = 3;           // Numero de velas del rango inicial
input int     InpSessionHour     = 8;           // Hora inicio sesion (hora servidor GMT) [London=8]
input int     InpSessionMinute   = 0;           // Minutos inicio sesion

input group "=== GESTION DE RIESGO ==="
input double  InpTP_Pips         = 20.0;        // Take Profit (pips)
input double  InpSL_Pips         = 15.0;        // Stop Loss (pips)
input double  InpBE_Pips         = 10.0;        // Breakeven trigger (pips, 0 = desactivado)
input double  InpRiskUSD         = 5.0;         // Riesgo en USD por operacion
input bool    InpUsePercentRisk  = false;        // Usar % del balance en lugar de USD
input double  InpRiskPercent     = 1.0;         // Riesgo en % si UsePercentRisk = true

input group "=== DIAS PERMITIDOS ==="
input bool    InpAllowMonday     = true;         // Lunes
input bool    InpAllowTuesday    = true;         // Martes
input bool    InpAllowWednesday  = true;         // Miercoles
input bool    InpAllowThursday   = true;         // Jueves
input bool    InpAllowFriday     = true;         // Viernes
input bool    InpAllowSaturday   = false;        // Sabado
input bool    InpAllowSunday     = false;        // Domingo

input group "=== CONFIGURACION GENERAL ==="
input ENUM_ORB_DIRECTION InpTradeDirection = DIR_BOTH;  // Direccion: Ambos / Solo Compras / Solo Ventas
input bool    InpOnlyOnePerDay   = true;         // Solo un trade por dia (false = re-entrada tras cierre)
input int     InpMagicNumber     = 20250404;     // Magic Number unico del EA
input string  InpComment         = "ORB_EUR";    // Comentario de las ordenes


//+------------------------------------------------------------------+
//|  VARIABLES GLOBALES                                              |
//+------------------------------------------------------------------+

CTrade   g_Trade;

// Configuracion
double   g_PipSize        = 0.0;

// Control de dia
int      g_PrevDay        = -1;

// Estado de la logica diaria
bool     g_RangeBuilt     = false;   // Rango ORB completamente definido
bool     g_OrdersPlaced   = false;   // Ordenes pendientes activas en el mercado
bool     g_TradeDone      = false;   // Actividad del dia terminada
bool     g_BEApplied      = false;   // Breakeven ya fue aplicado
bool     g_OppCancelled   = false;   // Se cancelo la orden opuesta (posicion activa)

// Niveles del rango
double   g_RangeHigh      = 0.0;
double   g_RangeLow       = 0.0;

// Tiempos de la sesion
datetime g_RangeStartTime = 0;
datetime g_RangeEndTime   = 0;

// Tickets de las ordenes pendientes
ulong    g_TicketBuy      = 0;
ulong    g_TicketSell     = 0;


//+------------------------------------------------------------------+
//| OnInit - Inicializacion del EA                                   |
//+------------------------------------------------------------------+
int OnInit()
{
   //--- Validar parametros de entrada
   if(InpRangeCandles < 1)
   {
      Alert("Error: InpRangeCandles debe ser >= 1");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(InpSL_Pips <= 0.0 || InpTP_Pips <= 0.0)
   {
      Alert("Error: SL y TP deben ser > 0 pips");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(!InpUsePercentRisk && InpRiskUSD <= 0.0)
   {
      Alert("Error: InpRiskUSD debe ser > 0");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(InpUsePercentRisk && (InpRiskPercent <= 0.0 || InpRiskPercent > 20.0))
   {
      Alert("Error: InpRiskPercent debe estar entre 0.1 y 20.0");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(InpSessionHour < 0 || InpSessionHour > 23)
   {
      Alert("Error: InpSessionHour debe ser entre 0 y 23");
      return INIT_PARAMETERS_INCORRECT;
   }
   if(InpSessionMinute < 0 || InpSessionMinute > 59)
   {
      Alert("Error: InpSessionMinute debe ser entre 0 y 59");
      return INIT_PARAMETERS_INCORRECT;
   }

   //--- Configurar objeto de trade
   g_Trade.SetExpertMagicNumber(InpMagicNumber);
   g_Trade.SetDeviationInPoints(30);
   g_Trade.SetAsyncMode(false);
   g_Trade.SetTypeFilling(DetectFillingType());

   //--- Calcular tamano del pip
   // Convencion moderna: 1 pip = 10 * _Point
   // Valido para: EURUSD 5-dig, USDJPY 3-dig, XAUUSD 2/3-dig, indices, etc.
   g_PipSize = _Point * 10.0;

   //--- Log de inicializacion
   Print("═══════════════════════════════════════════");
   Print("    ORB BREAKOUT EA v1.00 - EURUSD          ");
   Print("═══════════════════════════════════════════");
   PrintFormat("  Simbolo    : %s  |  TF: %s",   _Symbol, EnumToString(_Period));
   PrintFormat("  Digits     : %d  |  Point: %.5f  |  PipSize: %.5f", _Digits, _Point, g_PipSize);
   PrintFormat("  Sesion     : %02d:%02d  |  Rango: %d velas", InpSessionHour, InpSessionMinute, InpRangeCandles);
   PrintFormat("  SL=%.1f | TP=%.1f | BE=%.1f  (pips)", InpSL_Pips, InpTP_Pips, InpBE_Pips);
   PrintFormat("  RR         : 1:%.2f", InpTP_Pips / InpSL_Pips);
   PrintFormat("  Direccion  : %s", EnumToString(InpTradeDirection));
   PrintFormat("  Riesgo     : %s", InpUsePercentRisk
               ? StringFormat("%.2f%% del balance", InpRiskPercent)
               : StringFormat("$%.2f fijo", InpRiskUSD));
   PrintFormat("  Magic #    : %d  |  OnlyOnePerDay: %s", InpMagicNumber, (string)InpOnlyOnePerDay);
   Print("═══════════════════════════════════════════");

   return INIT_SUCCEEDED;
}


//+------------------------------------------------------------------+
//| OnDeinit - Limpieza al remover el EA                            |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   CancelAllPendingOrders();
   Comment("");
   PrintFormat("ORB EA detenido. Razon: %d", reason);
}


//+------------------------------------------------------------------+
//| OnTick - Logica principal ejecutada en cada tick                |
//+------------------------------------------------------------------+
void OnTick()
{
   datetime     now = TimeCurrent();
   MqlDateTime  dt;
   TimeToStruct(now, dt);

   //--- Detectar nuevo dia y reiniciar estado
   if(dt.day != g_PrevDay)
   {
      ResetDay(now, dt.day_of_week);
      g_PrevDay = dt.day;
   }

   //--- Filtro por dia de la semana
   if(!IsDayAllowed(dt.day_of_week))
   {
      UpdatePanel("DIA NO PERMITIDO");
      return;
   }

   //--- Si ya terminamos la actividad del dia, no hacer nada
   if(g_TradeDone)
   {
      UpdatePanel("COMPLETADO");
      return;
   }

   // ──────────────────────────────────────────────────
   // FASE 1: Esperar a que se complete la ventana
   //         del rango y luego construirlo
   // ──────────────────────────────────────────────────
   if(!g_RangeBuilt)
   {
      // Aun dentro de la ventana del rango
      if(now < g_RangeEndTime)
      {
         UpdatePanel("DEFINIENDO RANGO...");
         return;
      }

      // La ventana cerro: construir el rango con las velas historicas
      if(BuildRange())
      {
         g_RangeBuilt = true;
         PrintFormat("RANGO ORB DEFINIDO | H=%.5f  L=%.5f  Amplitud=%.5f pts",
                     g_RangeHigh, g_RangeLow, g_RangeHigh - g_RangeLow);
         PlacePendingOrders();
      }
      else
      {
         Print("BuildRange: no se encontraron velas validas en la ventana. Saltando dia.");
         g_TradeDone = true;
         UpdatePanel("SIN RANGO VALIDO");
      }
      return;
   }

   // ──────────────────────────────────────────────────
   // FASE 2: Gestionar ordenes activas y posicion
   // ──────────────────────────────────────────────────
   if(g_OrdersPlaced)
      ManageTrade();

   UpdatePanel(GetStatusStr());
}


//+------------------------------------------------------------------+
//| ResetDay - Reinicia todas las variables al inicio de un nuevo   |
//|            dia de trading                                        |
//+------------------------------------------------------------------+
void ResetDay(datetime now, int dayOfWeek)
{
   // Cancelar cualquier orden pendiente que haya quedado del dia anterior
   CancelAllPendingOrders();

   // Reiniciar variables de estado
   g_RangeHigh     = 0.0;
   g_RangeLow      = 0.0;
   g_RangeBuilt    = false;
   g_OrdersPlaced  = false;
   g_TradeDone     = false;
   g_BEApplied     = false;
   g_OppCancelled  = false;
   g_TicketBuy     = 0;
   g_TicketSell    = 0;

   // Calcular hora de inicio y fin del rango para HOY
   // Medianoche del servidor = segundos completos desde epoch / 86400 * 86400
   datetime midnight    = (now / 86400) * 86400;
   g_RangeStartTime     = midnight + InpSessionHour * 3600 + InpSessionMinute * 60;
   g_RangeEndTime       = g_RangeStartTime + (long)InpRangeCandles * PeriodSeconds(_Period);

   if(IsDayAllowed(dayOfWeek))
   {
      PrintFormat("Nuevo dia | Sesion: %s → Rango hasta: %s",
                  TimeToString(g_RangeStartTime, TIME_MINUTES),
                  TimeToString(g_RangeEndTime,   TIME_MINUTES));
   }
}


//+------------------------------------------------------------------+
//| BuildRange - Escanea el historial de velas dentro de la ventana |
//|              de sesion y extrae el High y Low del rango ORB      |
//+------------------------------------------------------------------+
bool BuildRange()
{
   double  hi    = 0.0;
   double  lo    = DBL_MAX;
   int     count = 0;
   int     total = iBars(_Symbol, _Period);

   // Recorrer desde la vela cerrada mas reciente hacia atras (i=0 esta en formacion)
   for(int i = 1; i < total; i++)
   {
      datetime t = iTime(_Symbol, _Period, i);

      if(t >= g_RangeEndTime)   continue;  // Vela posterior al rango → ignorar
      if(t < g_RangeStartTime)  break;     // Vela anterior a la sesion → salir del loop

      double barHi = iHigh(_Symbol, _Period, i);
      double barLo = iLow (_Symbol, _Period, i);

      if(barHi > hi) hi = barHi;
      if(barLo < lo) lo = barLo;
      count++;
   }

   PrintFormat("BuildRange: %d vela(s) procesada(s) en [%s - %s]",
               count,
               TimeToString(g_RangeStartTime, TIME_MINUTES),
               TimeToString(g_RangeEndTime,   TIME_MINUTES));

   if(count == 0 || hi <= lo || hi == 0.0)
      return false;

   g_RangeHigh = hi;
   g_RangeLow  = lo;
   return true;
}


//+------------------------------------------------------------------+
//| PlacePendingOrders - Coloca ordenes pendientes segun el filtro  |
//|   InpTradeDirection:                                             |
//|     DIR_BOTH      → BUY STOP en High + SELL STOP en Low         |
//|     DIR_BUY_ONLY  → Solo BUY STOP en el High                    |
//|     DIR_SELL_ONLY → Solo SELL STOP en el Low                    |
//+------------------------------------------------------------------+
void PlacePendingOrders()
{
   double ask      = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid      = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDist   = InpSL_Pips * g_PipSize;
   double tpDist   = InpTP_Pips * g_PipSize;
   double minDist  = (double)SymbolInfoInteger(_Symbol, SYMBOL_TRADE_STOPS_LEVEL) * _Point;
   double lots     = CalculateLotSize();
   bool   placed   = false;

   if(lots <= 0.0)
   {
      Print("PlacePendingOrders: lotaje invalido calculado. Saltando dia.");
      g_TradeDone = true;
      return;
   }

   // ─── BUY STOP en el High del rango ──────────────────────────
   if(InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_BUY_ONLY)
   {
      if(g_RangeHigh > ask + minDist)
      {
         double entry = NormalizeDouble(g_RangeHigh, _Digits);
         double sl    = NormalizeDouble(entry - slDist, _Digits);
         double tp    = NormalizeDouble(entry + tpDist, _Digits);

         if(g_Trade.BuyStop(lots, entry, _Symbol, sl, tp, ORDER_TIME_GTC, 0, InpComment))
         {
            g_TicketBuy = g_Trade.ResultOrder();
            Print("BUY STOP colocado | #", (string)g_TicketBuy,
                  "  E=", DoubleToString(entry, _Digits),
                  "  SL=", DoubleToString(sl, _Digits),
                  "  TP=", DoubleToString(tp, _Digits),
                  "  Lots=", DoubleToString(lots, 2));
            placed = true;
         }
         else
         {
            PrintFormat("Error BUY STOP: %s  Codigo: %d",
                        g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
         }
      }
      else
      {
         PrintFormat("BUY STOP omitido: ask=%.5f demasiado cerca del High=%.5f  (minDist=%.5f)",
                     ask, g_RangeHigh, minDist);
      }
   }

   // ─── SELL STOP en el Low del rango ──────────────────────────
   if(InpTradeDirection == DIR_BOTH || InpTradeDirection == DIR_SELL_ONLY)
   {
      if(g_RangeLow < bid - minDist)
      {
         double entry = NormalizeDouble(g_RangeLow, _Digits);
         double sl    = NormalizeDouble(entry + slDist, _Digits);
         double tp    = NormalizeDouble(entry - tpDist, _Digits);

         if(g_Trade.SellStop(lots, entry, _Symbol, sl, tp, ORDER_TIME_GTC, 0, InpComment))
         {
            g_TicketSell = g_Trade.ResultOrder();
            Print("SELL STOP colocado | #", (string)g_TicketSell,
                  "  E=", DoubleToString(entry, _Digits),
                  "  SL=", DoubleToString(sl, _Digits),
                  "  TP=", DoubleToString(tp, _Digits),
                  "  Lots=", DoubleToString(lots, 2));
            placed = true;
         }
         else
         {
            PrintFormat("Error SELL STOP: %s  Codigo: %d",
                        g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
         }
      }
      else
      {
         PrintFormat("SELL STOP omitido: bid=%.5f demasiado cerca del Low=%.5f  (minDist=%.5f)",
                     bid, g_RangeLow, minDist);
      }
   }

   g_OrdersPlaced = placed;

   if(!placed)
   {
      Print("Sin ordenes colocadas. El precio ya esta fuera del rango. Dia terminado.");
      g_TradeDone = true;
   }
}


//+------------------------------------------------------------------+
//| ManageTrade - Logica de gestion: detecta activacion, cancela    |
//|               la orden opuesta y aplica Breakeven               |
//+------------------------------------------------------------------+
void ManageTrade()
{
   ulong posTicket = FindOpenPosition();

   // ─── CASO 1: Posicion activa ─────────────────────────────────
   if(posTicket > 0)
   {
      // Primera vez que detectamos la posicion activa:
      // cancelar la orden pendiente opuesta
      if(!g_OppCancelled)
      {
         CancelAllPendingOrders();
         g_OppCancelled = true;
         Print("Breakout activado! Posicion #", (string)posTicket,
               " | Orden opuesta cancelada.");
      }

      // Gestionar Breakeven si esta habilitado
      if(!g_BEApplied && InpBE_Pips > 0.0)
         ApplyBreakeven(posTicket);

      return;
   }

   // ─── CASO 2: Posicion cerrada (vino de una activacion previa) ─
   if(g_OppCancelled)
   {
      if(InpOnlyOnePerDay)
      {
         // Modo conservador: un solo trade, marcar dia como terminado
         g_TradeDone = true;
         Print("Posicion cerrada por TP/SL/BE. Dia completado (OnlyOnePerDay=ON).");
      }
      else
      {
         // Modo agresivo: re-colocar ordenes en los mismos niveles del rango
         Print("Posicion cerrada. Re-colocando ordenes en el rango existente (OnlyOnePerDay=OFF)...");
         g_OppCancelled = false;
         g_BEApplied    = false;
         g_TicketBuy    = 0;
         g_TicketSell   = 0;
         PlacePendingOrders();
      }
      return;
   }

   // ─── CASO 3: Sin posicion activa, sin activacion previa ──────
   // Verificar si las ordenes pendientes siguen vivas
   bool buyPending  = (g_TicketBuy  > 0 && IsOrderPending(g_TicketBuy));
   bool sellPending = (g_TicketSell > 0 && IsOrderPending(g_TicketSell));

   if(!buyPending && !sellPending)
   {
      // Ambas ordenes desaparecieron sin generar posicion
      g_TradeDone = true;
      Print("Ordenes expiradas/canceladas sin activacion. Dia terminado.");
   }
}


//+------------------------------------------------------------------+
//| ApplyBreakeven - Mueve el SL al precio de entrada cuando el     |
//|                  trade alcanza el umbral de Breakeven            |
//+------------------------------------------------------------------+
void ApplyBreakeven(ulong ticket)
{
   if(!PositionSelectByTicket(ticket)) return;

   ENUM_POSITION_TYPE posType   = (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
   double             openPrice = PositionGetDouble(POSITION_PRICE_OPEN);
   double             currentSL = PositionGetDouble(POSITION_SL);
   double             currentTP = PositionGetDouble(POSITION_TP);
   double             beDistance = InpBE_Pips * g_PipSize;
   double             bid       = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double             ask       = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double             newSL     = 0.0;
   bool               doModify  = false;

   if(posType == POSITION_TYPE_BUY)
   {
      // BUY: precio bid debe superar entry + beDistance
      if(bid >= openPrice + beDistance)
      {
         newSL = NormalizeDouble(openPrice, _Digits);
         if(newSL > currentSL)
            doModify = true;
      }
   }
   else // POSITION_TYPE_SELL
   {
      // SELL: precio ask debe caer por debajo de entry - beDistance
      if(ask <= openPrice - beDistance)
      {
         newSL = NormalizeDouble(openPrice, _Digits);
         if(currentSL == 0.0 || newSL < currentSL)
            doModify = true;
      }
   }

   if(doModify)
   {
      if(g_Trade.PositionModify(ticket, newSL, currentTP))
      {
         g_BEApplied = true;
         PrintFormat("BREAKEVEN aplicado | #%s  Nuevo SL=%.5f", (string)ticket, newSL);
      }
      else
      {
         PrintFormat("Error aplicando BE: %s (%d)",
                     g_Trade.ResultRetcodeDescription(), g_Trade.ResultRetcode());
      }
   }
}


//+------------------------------------------------------------------+
//| CalculateLotSize - Calcula el lotaje basado en el riesgo        |
//|                    definido (USD o % del balance)                |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = InpUsePercentRisk
                       ? (balance * InpRiskPercent / 100.0)
                       : InpRiskUSD;

   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickSize <= 0.0 || tickValue <= 0.0)
   {
      PrintFormat("CalculateLotSize: tick info invalida (tickValue=%.5f tickSize=%.5f)",
                  tickValue, tickSize);
      return 0.0;
   }

   // Valor monetario por pip por lote estandar (en divisa de la cuenta)
   double valuePerPip = tickValue * (g_PipSize / tickSize);
   if(valuePerPip <= 0.0) return 0.0;

   // Formula: Lots = Riesgo$ / (SL_pips * $/pip/lot)
   double lots    = riskAmount / (InpSL_Pips * valuePerPip);
   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   // Redondear hacia abajo al step mas cercano
   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

   PrintFormat("Lotaje calculado: %.2f  (Riesgo=$%.2f | $/pip=$%.4f | Balance=$%.2f)",
               lots, riskAmount, valuePerPip, balance);
   return lots;
}


//+------------------------------------------------------------------+
//| FindOpenPosition - Busca una posicion abierta de este EA        |
//|                    en el simbolo actual                          |
//+------------------------------------------------------------------+
ulong FindOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      ulong ticket = PositionGetTicket(i);
      if(PositionGetString(POSITION_SYMBOL)  == _Symbol &&
         PositionGetInteger(POSITION_MAGIC)  == (long)InpMagicNumber)
         return ticket;
   }
   return 0;
}


//+------------------------------------------------------------------+
//| IsOrderPending - Verifica si una orden pendiente sigue activa  |
//+------------------------------------------------------------------+
bool IsOrderPending(ulong ticket)
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
      if(OrderGetTicket(i) == ticket) return true;
   return false;
}


//+------------------------------------------------------------------+
//| CancelAllPendingOrders - Cancela todas las ordenes pendientes   |
//|                          de este EA en el simbolo actual         |
//+------------------------------------------------------------------+
void CancelAllPendingOrders()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      ulong ticket = OrderGetTicket(i);
      if(OrderGetInteger(ORDER_MAGIC)  == (long)InpMagicNumber &&
         OrderGetString (ORDER_SYMBOL) == _Symbol)
      {
         if(g_Trade.OrderDelete(ticket))
            Print("Orden cancelada: #", (string)ticket);
         else
            PrintFormat("Error cancelando #%s: %s (%d)",
                        (string)ticket,
                        g_Trade.ResultRetcodeDescription(),
                        g_Trade.ResultRetcode());
      }
   }
   g_TicketBuy  = 0;
   g_TicketSell = 0;
}


//+------------------------------------------------------------------+
//| IsDayAllowed - Verifica si el dia de la semana esta permitido  |
//+------------------------------------------------------------------+
bool IsDayAllowed(int dow)
{
   switch(dow)
   {
      case 0: return InpAllowSunday;
      case 1: return InpAllowMonday;
      case 2: return InpAllowTuesday;
      case 3: return InpAllowWednesday;
      case 4: return InpAllowThursday;
      case 5: return InpAllowFriday;
      case 6: return InpAllowSaturday;
      default: return false;
   }
}


//+------------------------------------------------------------------+
//| DetectFillingType - Detecta el tipo de relleno compatible con   |
//|                     el broker actual                             |
//+------------------------------------------------------------------+
ENUM_ORDER_TYPE_FILLING DetectFillingType()
{
   uint filling = (uint)SymbolInfoInteger(_Symbol, SYMBOL_FILLING_MODE);
   if((filling & SYMBOL_FILLING_FOK) != 0) return ORDER_FILLING_FOK;
   if((filling & SYMBOL_FILLING_IOC) != 0) return ORDER_FILLING_IOC;
   return ORDER_FILLING_RETURN;
}


//+------------------------------------------------------------------+
//| GetStatusStr - Retorna el estado actual del EA como texto       |
//+------------------------------------------------------------------+
string GetStatusStr()
{
   if(g_TradeDone)     return "COMPLETADO";
   if(g_OppCancelled)  return "EN POSICION";
   if(g_OrdersPlaced)  return "ESPERANDO RUPTURA";
   if(g_RangeBuilt)    return "RANGO DEFINIDO";
   return "DEFINIENDO RANGO";
}


//+------------------------------------------------------------------+
//| UpdatePanel - Muestra informacion del EA en el grafico          |
//+------------------------------------------------------------------+
void UpdatePanel(const string status)
{
   string div = "─────────────────────────────\n";
   string be  = g_BEApplied      ? "APLICADO"
              : (InpBE_Pips > 0) ? "PENDIENTE"
              :                    "DESACTIVADO";

   string txt =
      "  ORB BREAKOUT EA  v1.00 - EURUSD\n"                               + div +
      "  Simbolo : " + _Symbol + "   TF: " + EnumToString(_Period) + "\n" +
      "  Sesion  : " + TimeToString(g_RangeStartTime, TIME_MINUTES) +
      " → " + TimeToString(g_RangeEndTime, TIME_MINUTES) + "\n"           +
      "  H Rango : " + DoubleToString(g_RangeHigh, _Digits) + "\n"        +
      "  L Rango : " + DoubleToString(g_RangeLow,  _Digits) + "\n"        + div +
      "  Direcc  : " + EnumToString(InpTradeDirection)       + "\n"        +
      "  Estado  : " + status + "\n"                                        +
      "  BE      : " + be + "\n"                                            +
      "  BUY  #  : " + (string)g_TicketBuy  + "\n"                         +
      "  SELL #  : " + (string)g_TicketSell + "\n"                         + div;

   Comment(txt);
}

